import { Injectable, inject, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, of, throwError } from 'rxjs';
import { environment } from 'src/environments/environment';
import { RsvpRequest, RsvpResponse, StatusPresenca } from './rsvp.model';
import { ConviteAdminRequest } from '../auth/admin.model';

// Mock invite database
const MOCK_INVITES: RsvpResponse[] = [
  { id: 1, codigo: 'TG001', familia: 'Família Silva',
    convidados: [
      { id: 1, nome: 'Maria Silva',    status: 'PENDENTE' },
      { id: 2, nome: 'João Silva',     status: 'PENDENTE' },
      { id: 3, nome: 'Ana Silva',      status: 'PENDENTE' },
    ],
  },
  { id: 2, codigo: 'TG002', familia: 'Família Oliveira',
    convidados: [
      { id: 4, nome: 'Carlos Oliveira',   status: 'PENDENTE' },
      { id: 5, nome: 'Fernanda Oliveira', status: 'PENDENTE' },
    ],
  },
  { id: 3, codigo: 'TG003', familia: 'Família Santos',
    convidados: [
      { id: 6, nome: 'Pedro Santos',  status: 'PENDENTE' },
      { id: 7, nome: 'Lucia Santos',  status: 'PENDENTE' },
      { id: 8, nome: 'Marco Santos',  status: 'PENDENTE' },
      { id: 9, nome: 'Sofia Santos',  status: 'PENDENTE' },
    ],
  },
  { id: 4, codigo: 'TG004', familia: 'Família Costa',
    convidados: [
      { id: 10, nome: 'Rafael Costa', status: 'PENDENTE' },
      { id: 11, nome: 'Julia Costa',  status: 'PENDENTE' },
    ],
  },
  { id: 5, codigo: 'TG005', familia: 'Rodrigo Mendes',
    convidados: [
      { id: 12, nome: 'Rodrigo Mendes', status: 'PENDENTE' },
    ],
  },
];

@Injectable({ providedIn: 'root' })
export class ConviteService {
  private http = inject(HttpClient);
  private readonly api = `${environment.apiUrl}/convites`;
  private useMock = true;

  private _allConvites = signal<RsvpResponse[]>(MOCK_INVITES);
  readonly allConvites = this._allConvites.asReadonly();

  buscar(codigo: string): Observable<RsvpResponse> {
    if (this.useMock) {
      const found = this._allConvites().find(
        c => c.codigo.toUpperCase() === codigo.toUpperCase()
      );
      if (!found) return throwError(() => new Error('Código não encontrado'));
      return of({ ...found, convidados: [...found.convidados] });
    }
    return this.http.get<RsvpResponse>(`${this.api}/${codigo}`);
  }

  confirmar(codigo: string, rsvps: RsvpRequest[]): Observable<void> {
    if (this.useMock) {
      this._allConvites.update(convites =>
        convites.map(c => {
          if (c.codigo !== codigo) return c;
          return {
            ...c,
            convidados: c.convidados.map(g => {
              const update = rsvps.find(r => r.convidadoId === g.id);
              return update ? { ...g, status: update.status } : g;
            }),
          };
        })
      );
      return of(void 0);
    }
    return this.http.post<void>(`${this.api}/${codigo}/confirmar`, rsvps);
  }

  criar(dto: ConviteAdminRequest): Observable<RsvpResponse> {
    if (this.useMock) {
      const novo: RsvpResponse = {
        id: Date.now(),
        codigo: dto.codigo.toUpperCase(),
        familia: dto.familia,
        convidados: dto.convidados.map((nome, i) => ({
          id: Date.now() + i,
          nome,
          status: 'PENDENTE' as StatusPresenca,
        })),
      };
      this._allConvites.update(c => [...c, novo]);
      return of(novo);
    }
    return this.http.post<RsvpResponse>(this.api, dto);
  }

  deletar(id: number): Observable<void> {
    if (this.useMock) {
      this._allConvites.update(c => c.filter(cv => cv.id !== id));
      return of(void 0);
    }
    return this.http.delete<void>(`${this.api}/${id}`);
  }

  statsSummary() {
    const all = this._allConvites();
    const convidados = all.flatMap(c => c.convidados);
    return {
      total: convidados.length,
      confirmados: convidados.filter(g => g.status === 'CONFIRMADO').length,
      pendentes:   convidados.filter(g => g.status === 'PENDENTE').length,
      talvez:      convidados.filter(g => g.status === 'TALVEZ').length,
      naoVem:      convidados.filter(g => g.status === 'NAO_VEM').length,
    };
  }
}
